-- ============================================
-- Legislacao full-site: teresa-surita / Camara Dados Abertos / projetos_lei
-- Coverage ampliado parcial: Lote A autoria principal Camara
-- ============================================
-- Fonte oficial: Camara dos Deputados - Dados Abertos
--   https://dadosabertos.camara.leg.br/api/v2/deputados/160608
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}
--   https://dadosabertos.camara.leg.br/api/v2/proposicoes/{id}/autores
--
-- Artefato de auditoria:
--   fonte interna de curadoria
--
-- Coverage:
--   coverage_id    = teresa-surita-camara-autoria-principal-ampliado-parcial-lote-a-20260506
--   coverage_scope = inventario_ampliado_parcial_camara_autoria_principal_lote_a_20260506
--
-- Filtro factual: das 88 rows Camara legacy existentes, somente 77
-- foram marcadas com coverage_id porque a API oficial confirmou
-- idDeputado=160608, tipo Deputado(a), ordemAssinatura=1.
-- 11 rows permanecem sem coverage por coautoria/sem autoria verificavel.
--
-- Esta migration NAO escreve em legislacao_mandato_executivo.
-- Esta migration NAO insere, deleta ou trunca rows.
-- ============================================

DO $$
DECLARE
  cand_id uuid;
  total_pl int;
  target_present int;
  target_with_other_coverage int;
  lme_count int;
BEGIN
  SELECT id INTO cand_id FROM candidatos WHERE slug = 'teresa-surita';

  IF cand_id IS NULL THEN
    RAISE NOTICE 'teresa-surita: candidato ausente neste banco local/CI minimo; coverage Camara pulado';
    RETURN;
  END IF;

  SELECT count(*) INTO total_pl FROM projetos_lei WHERE candidato_id = cand_id;
  IF total_pl <> 88 THEN
    RAISE EXCEPTION 'Pre-condicao teresa-surita: esperadas 88 rows legacy em projetos_lei, encontradas %', total_pl;
  END IF;

  SELECT count(*) INTO target_present
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND fonte = 'Camara'
    AND proposicao_id_api IN ('560644', '550128', '550129', '543070', '531893', '527225', '560587', '550833', '522798', '495439', '550837', '549504', '549501', '543680', '543076', '538749', '545373', '531892', '527124', '521563', '518425', '512504', '510919', '509082', '507752', '507708', '507701', '505021', '493173', '169829', '537810', '530297', '522800', '519366', '515396', '512376', '509108', '507758', '507748', '507705', '507699', '499495', '234019', '15801', '537809', '530087', '522799', '519364', '514572', '512374', '509084', '507757', '507745', '507704', '507698', '497042', '191118', '526255', '523411', '521453', '509407', '507760', '507751', '507706', '507700', '241888', '169464', '519363', '514025', '512373', '509083', '507756', '507710', '507703', '507695', '181003', '518070');
  IF target_present <> 77 THEN
    RAISE EXCEPTION 'Pre-condicao teresa-surita: esperadas 77 rows alvo Camara presentes, encontradas %', target_present;
  END IF;

  SELECT count(*) INTO target_with_other_coverage
  FROM projetos_lei
  WHERE candidato_id = cand_id
    AND proposicao_id_api IN ('560644', '550128', '550129', '543070', '531893', '527225', '560587', '550833', '522798', '495439', '550837', '549504', '549501', '543680', '543076', '538749', '545373', '531892', '527124', '521563', '518425', '512504', '510919', '509082', '507752', '507708', '507701', '505021', '493173', '169829', '537810', '530297', '522800', '519366', '515396', '512376', '509108', '507758', '507748', '507705', '507699', '499495', '234019', '15801', '537809', '530087', '522799', '519364', '514572', '512374', '509084', '507757', '507745', '507704', '507698', '497042', '191118', '526255', '523411', '521453', '509407', '507760', '507751', '507706', '507700', '241888', '169464', '519363', '514025', '512373', '509083', '507756', '507710', '507703', '507695', '181003', '518070')
    AND coverage_id IS NOT NULL
    AND coverage_id <> 'teresa-surita-camara-autoria-principal-ampliado-parcial-lote-a-20260506';
  IF target_with_other_coverage <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao teresa-surita: % rows alvo ja tem coverage_id divergente', target_with_other_coverage;
  END IF;

  SELECT count(*) INTO lme_count FROM legislacao_mandato_executivo WHERE candidato_id = cand_id;
  IF lme_count <> 0 THEN
    RAISE EXCEPTION 'Pre-condicao teresa-surita: legislacao_mandato_executivo deve permanecer 0, encontrado %', lme_count;
  END IF;
END $$;

